mapper.select:
SELECT w.* FROM work w

    w.deleted = 0
    AND w.status = #{status}
    AND w.submitter_id = #{submitterId}
    AND w.batch_id = #{batchId}

        AND (w.title LIKE CONCAT('%', #{keyword}, '%')
        OR w.tech_stack LIKE CONCAT('%', #{keyword}, '%')
        OR w.advisor LIKE CONCAT('%', #{keyword}, '%'))


        AND w.tech_stack LIKE CONCAT('%', #{techStack}, '%')


ORDER BY w.create_time DESC
